const questions=[{category:"MySQL",question:"Quelle commande cree une nouvelle base de donnees ?",options:["<code>CREATE DATABASE</code>","<code>NEW DATABASE</code>","<code>ADD DATABASE</code>","<code>INIT DATABASE</code>"],answer:0,explanation:"<code>CREATE DATABASE nom;</code> est la commande SQL standard."},{category:"MySQL",question:"Quelle fonction obtient la valeur minimale d'une colonne ?",options:["<code>MIN()</code>","<code>LOWEST()</code>","<code>SMALL()</code>","<code>LEAST()</code>"],answer:0,explanation:"<code>MIN()</code> retourne la plus petite valeur."},{category:"MySQL",question:"Quelle clause groupe les resultats ?",options:["<code>GROUP BY</code>","<code>ORDER BY</code>","<code>SORT BY</code>","<code>CATEGORIZE BY</code>"],answer:0,explanation:"<code>GROUP BY</code> regroupe les lignes."},{category:"MySQL",question:"Quelle commande recupere des donnees ?",options:["<code>GET</code>","<code>SELECT</code>","<code>FETCH</code>","<code>RETRIEVE</code>"],answer:1,explanation:"<code>SELECT</code> lit des donnees."},{category:"MySQL",question:"Quelle commande definit une cle etrangere ?",options:["<code>FOREIGN KEY</code>","<code>ADD FOREIGN KEY</code>","<code>CONSTRAINT</code>","<code>RELATIONSHIP</code>"],answer:0,explanation:"<code>FOREIGN KEY</code> definit une cle etrangere."},{category:"MySQL",question:"Quelle commande execute une procedure stockee ?",options:["<code>EXECUTE</code>","<code>CALL</code>","<code>RUN</code>","<code>START</code>"],answer:1,explanation:"<code>CALL</code> execute une procedure stockee."},{category:"MySQL",question:"Quelle commande renomme une table ?",options:["<code>RENAME TABLE</code>","<code>CHANGE TABLE</code>","<code>MODIFY TABLE</code>","<code>ALTER TABLE</code>"],answer:0,explanation:"<code>RENAME TABLE ancien TO nouveau;</code>"},{category:"MySQL",question:"Quelle commande affiche toutes les donnees ?",options:["<code>SHOW COLUMNS</code>","<code>LIST COLUMNS</code>","<code>DISPLAY COLUMNS</code>","<code>SELECT * FROM</code>"],answer:3,explanation:"<code>SELECT * FROM table</code> affiche tout."},{category:"HTML",question:"La partie HEAD contient...",options:["Toutes les balises","Les balises du BODY","La balise TITLE","Aucune"],answer:2,explanation:"Le HEAD contient les metadonnees dont TITLE."},{category:"HTML",question:"Un document Web commence par :",options:["<code>html</code>","<code>&lt;htlm&gt;</code>","<code>&lt;html&gt;</code>"],answer:2,explanation:"Un document commence par <code>&lt;html&gt;</code>."},{category:"HTML",question:"Comment mettre un fond jaune ?",options:["<code>&lt;BACKGROUND&gt;yellow&lt;/BACKGROUND&gt;</code>","<code>&lt;BODY COLOR=\"yellow\"&gt;</code>","<code>&lt;BODY BGCOLOR=\"yellow\"&gt;</code>","<code>&lt;BODY BGCOLOR=\"jaune\"&gt;</code>"],answer:2,explanation:"<code>BGCOLOR</code> definit la couleur de fond."},{category:"HTML",question:"Pour un style interne, on utilise :",options:["<code>&lt;style&gt;</code>","<code>style</code>","<code>&lt;style=\"text/css\"&gt;</code>"],answer:0,explanation:"La balise <code>&lt;style&gt;</code> dans le HEAD."},{category:"HTML",question:"Que signifie HTML ?",options:["Home Tool Markup Language","Hyperlinks and Text Markup Language","Hyper Text Markup Language"],answer:2,explanation:"HTML = HyperText Markup Language."},{category:"HTML",question:"Quelle balise pour une image cliquable ?",options:["<code>&lt;img&gt;</code>","<code>&lt;a&gt;</code>","<code>&lt;link&gt;</code>","<code>&lt;button&gt;</code>"],answer:1,explanation:"On entoure l'image avec <code>&lt;a&gt;</code>."},{category:"HTML",question:"Quelle balise definit une cellule ?",options:["<code>&lt;td&gt;</code>","<code>&lt;th&gt;</code>","<code>&lt;tr&gt;</code>","<code>&lt;thead&gt;</code>"],answer:0,explanation:"<code>&lt;td&gt;</code> = table data."},{category:"HTML",question:"Quelle balise definit un lien ?",options:["<code>&lt;nav&gt;</code>","<code>&lt;link&gt;</code>","<code>&lt;a&gt;</code>","<code>&lt;menu&gt;</code>"],answer:2,explanation:"<code>&lt;a&gt;</code> cree un lien hypertexte."},{category:"CSS",question:"Quelle propriete definit la couleur du texte ?",options:["<code>color</code>","<code>background-color</code>","<code>border-color</code>","<code>text-color</code>"],answer:0,explanation:"<code>color</code> definit la couleur du texte."},{category:"CSS",question:"Comment commenter en CSS ?",options:["<code>/* commentaire */</code>","<code>// commentaire</code>","<code>commentaire</code>"],answer:0,explanation:"CSS utilise <code>/* ... */</code>."},{category:"HTML",question:"Quelle balise cree une liste ordonnee ?",options:["<code>&lt;ul&gt;</code>","<code>&lt;ol&gt;</code>","<code>&lt;li&gt;</code>","<code>&lt;dl&gt;</code>"],answer:1,explanation:"<code>&lt;ol&gt;</code> = ordered list."},{category:"CSS",question:"Quelle propriete definit la largeur ?",options:["<code>width</code>","<code>height</code>","<code>size</code>","<code>margin</code>"],answer:0,explanation:"<code>width</code> definit la largeur."},{category:"CSS",question:"Quelle propriete definit la taille de police ?",options:["<code>font-size</code>","<code>font-family</code>","<code>text-size</code>","<code>size</code>"],answer:0,explanation:"<code>font-size</code> controle la taille."},{category:"HTML",question:"Quelle balise ajoute une ancre ?",options:["<code>&lt;a&gt;</code>","<code>&lt;link&gt;</code>","<code>&lt;anchor&gt;</code>","<code>&lt;ref&gt;</code>"],answer:0,explanation:"<code>&lt;a&gt;</code> pour liens et ancres."},{category:"CSS",question:"Quelle propriete definit la hauteur ?",options:["<code>height</code>","<code>width</code>","<code>size</code>","<code>margin</code>"],answer:0,explanation:"<code>height</code> definit la hauteur."},{category:"CSS",question:"Quelle propriete definit la police ?",options:["<code>font-family</code>","<code>font-size</code>","<code>font-weight</code>","<code>font-style</code>"],answer:0,explanation:"<code>font-family</code> specifie la police."},{category:"JavaScript",question:"Si ville = \"CASABLANCA\", <code>ville.charAt(4)</code> retourne :",options:["A","B","AB"],answer:1,explanation:"C(0)A(1)S(2)A(3)B(4) → 'B'."},{category:"JavaScript",question:"Syntaxe correcte pour un Array ?",options:["<code>var f='a','b'</code>","<code>var f=['a','b']</code>","<code>var f=(1:'a',2:'b')</code>"],answer:1,explanation:"Crochets <code>[]</code> pour les tableaux."},{category:"JavaScript",question:"Bonne syntaxe de for ?",options:["<code>for j=1 to 10</code>","<code>for(j&lt;=10;j++)</code>","<code>for(j=0;j&lt;=10;j++)</code>","<code>for(j=0;j&lt;=10)</code>"],answer:2,explanation:"<code>for(init;condition;increment)</code>."},{category:"JavaScript",question:"x n'est pas egal a 7 ?",options:["<code>if(x&lt;&gt;7)</code>","<code>if x=!7</code>","<code>if x&lt;&gt;7</code>","<code>if(x!=7)</code>"],answer:3,explanation:"<code>!=</code> est l'operateur d'inegalite."},{category:"JavaScript",question:"JavaScript date :",options:["Des annees 1970","Des annees 1980","Des annees 1990","Des annees 2000"],answer:2,explanation:"Cree en 1995 par Brendan Eich."},{category:"JavaScript",question:"Le langage JavaScript :",options:["Peut etre interprete par le navigateur","Ne peut etre interprete que cote serveur"],answer:0,explanation:"JS est interprete par le navigateur."},{category:"JavaScript",question:"Le createur de JavaScript :",options:["Bill Gates","Brendan Eich","Guido van Rossum","James Gosling"],answer:1,explanation:"Brendan Eich en 1995."},{category:"JavaScript",question:"On separe les instructions par :",options:["Un passage a la ligne","Un point-virgule"],answer:1,explanation:"Le point-virgule separe les instructions."},{category:"PHP",question:"Que signifie PHP ?",options:["Personal Home Page","Hypertext Preprocessor","Pretext Hypertext Processor","Preprocessor Home Page"],answer:1,explanation:"PHP: Hypertext Preprocessor."},{category:"PHP",question:"Un script PHP commence par :",options:["<code>&lt;php</code>","<code>&lt;?php</code>","<code>&lt;?</code>","<code>&lt;php?</code>"],answer:1,explanation:"<code>&lt;?php</code> est la balise standard."},{category:"PHP",question:"Logiciel necessaire pour PHP ?",options:["Dreamweaver","PHP","Apache","IIS"],answer:1,explanation:"L'interpreteur PHP est necessaire."},{category:"PHP",question:"Version PHP avec Try/catch ?",options:["PHP 4","PHP 5","PHP 5.3","PHP 7.2"],answer:1,explanation:"PHP 5 a introduit try/catch."},{category:"PHP",question:"Stocker 55 dans nbr ?",options:["<code>int $nbr=55;</code>","<code>int nbr=55;</code>","<code>$nbr=55;</code>","<code>55=$nbr;</code>"],answer:2,explanation:"Variables PHP avec <code>$</code>, pas de type."},{category:"PHP",question:"Variables de session ?",options:["<code>$GLOBALS</code>","<code>$_SERVER</code>","<code>$SESSION</code>","<code>$_SESSION</code>"],answer:3,explanation:"<code>$_SESSION</code> avec underscore."},{category:"PHP",question:"Fonction pour creer un tableau ?",options:["<code>array()</code>","<code>new array()</code>","<code>array[]</code>","<code>$array()</code>"],answer:0,explanation:"<code>array()</code> ou <code>[]</code> depuis PHP 5.4."},{category:"PHP",question:"Connecter MySQL en PHP ?",options:["<code>mysql_connect()</code>","<code>mysql_query()</code>","<code>mysql_close()</code>","Aucune"],answer:0,explanation:"<code>mysql_connect()</code> (deprecie). Utilisez PDO."}];
let currentQuestion=0,score=0,selectedOption=-1,answered=false,shuffledQuestions=[],answers=[],timerInterval=null,timerSeconds=0;
function startTimer(){timerSeconds=0;clearInterval(timerInterval);timerInterval=setInterval(()=>{timerSeconds++;document.getElementById('timer').textContent=String(Math.floor(timerSeconds/60)).padStart(2,'0')+':'+String(timerSeconds%60).padStart(2,'0');},1000);}function stopTimer(){clearInterval(timerInterval);}function shuffle(a){const b=[...a];for(let i=b.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[b[i],b[j]]=[b[j],b[i]];}return b;}
function startQuiz(){shuffledQuestions=shuffle(questions);currentQuestion=0;score=0;answers=[];document.getElementById('start-screen').style.display='none';document.getElementById('quiz-area').style.display='block';document.getElementById('results').style.display='none';showQuestion();startTimer();}
function showQuestion(){selectedOption=-1;answered=false;const q=shuffledQuestions[currentQuestion],t=shuffledQuestions.length;document.getElementById('progress-text').textContent=`Question ${currentQuestion+1} / ${t}`;document.getElementById('progress-fill').style.width=((currentQuestion+1)/t*100)+'%';document.getElementById('btn-validate').style.display='inline-block';document.getElementById('btn-validate').disabled=true;document.getElementById('btn-next').style.display='none';let h=`<span class="category-badge cat-${q.category.toLowerCase()}">${q.category}</span><div class="question-text">${q.question}</div><ul class="options">`;q.options.forEach((o,i)=>{h+=`<li onclick="selectOption(${i})">${o}</li>`;});h+=`</ul><div class="explanation" id="explanation">${q.explanation}</div>`;document.getElementById('question-card').innerHTML=h;}
function selectOption(i){if(answered)return;selectedOption=i;document.getElementById('btn-validate').disabled=false;document.querySelectorAll('.options li').forEach((e,x)=>{e.classList.toggle('selected',x===i);});}
function validateAnswer(){if(selectedOption===-1||answered)return;answered=true;const q=shuffledQuestions[currentQuestion],c=q.answer,ok=selectedOption===c;if(ok)score++;answers.push({question:q,selected:selectedOption,correct:ok});document.querySelectorAll('.options li').forEach((e,x)=>{e.classList.add('disabled');if(x===c)e.classList.add('correct');if(x===selectedOption&&!ok)e.classList.add('wrong');});document.getElementById('explanation').style.display='block';document.getElementById('btn-validate').style.display='none';if(currentQuestion<shuffledQuestions.length-1)document.getElementById('btn-next').style.display='inline-block';else setTimeout(showResults,800);}
function nextQuestion(){currentQuestion++;showQuestion();}
function showResults(){stopTimer();document.getElementById('quiz-area').style.display='none';const r=document.getElementById('results');r.style.display='block';const t=shuffledQuestions.length,p=Math.round(score/t*100);let lc,m,d;if(p>=80){lc='level-excellent';m='Excellent !';d='Solide base.';}else if(p>=60){lc='level-good';m='Bon niveau !';d='Revoyez les erreurs.';}else if(p>=40){lc='level-average';m='Moyen.';d='Travaillez vos points faibles.';}else{lc='level-weak';m='A renforcer.';d='Reprenez les bases.';}const cats=['MySQL','HTML','CSS','JavaScript','PHP'];const cs={};cats.forEach(c=>cs[c]={total:0,correct:0});answers.forEach(a=>{cs[a.question.category].total++;if(a.correct)cs[a.question.category].correct++;});let ch='<div class="cat-scores">';cats.forEach(c=>{const s=cs[c],pc=s.total>0?Math.round(s.correct/s.total*100):0;let co='#e74c3c';if(pc>=80)co='#27ae60';else if(pc>=60)co='#2980b9';else if(pc>=40)co='#f39c12';ch+=`<div class="cat-score-card"><div class="cat-name"><span class="category-badge cat-${c.toLowerCase()}">${c}</span></div><div class="cat-pct" style="color:${co}">${pc}%</div><div class="cat-detail">${s.correct}/${s.total}</div></div>`;});ch+='</div>';r.innerHTML=`<div class="score-circle ${lc}">${p}%<span class="label">${score}/${t}</span></div><div class="level-message">${m}</div><div class="level-detail">${d}</div>${ch}<div class="btn-container" style="margin-top:30px"><button class="btn btn-primary" onclick="startQuiz()">Recommencer</button><button class="btn btn-restart" onclick="retryFailed()" style="margin-left:10px">Retravailler mes erreurs</button><button class="btn btn-restart" onclick="location.href='/dashboard'" style="margin-left:10px">Accueil</button></div>`;fetch('/api/scores',{method:'POST',headers:{'Content-Type':'application/json','X-CSRF-TOKEN':document.querySelector('meta[name=csrf-token]').content},body:JSON.stringify({qcm_name:'qcm9',score,total:t,percentage:p,duration_seconds:timerSeconds})});}
function retryFailed(){const f=answers.filter(a=>!a.correct);if(!f.length){alert('Aucune erreur !');return;}shuffledQuestions=f.map(x=>({...x.question}));currentQuestion=0;score=0;answers=[];document.getElementById('start-screen').style.display='none';document.getElementById('quiz-area').style.display='block';document.getElementById('results').style.display='none';showQuestion();startTimer();}
</script>
@endsection
